#include <stdio.h>
#include <math.h>
#include <stdlib.h>

#define WIDTH 800
#define HEIGHT 600

typedef struct {
    double x, y, z;
} Vec3;

Vec3 vec3(double x, double y, double z) {
    Vec3 v = {x, y, z};
    return v;
}

Vec3 add(Vec3 a, Vec3 b) {
    return vec3(a.x + b.x, a.y + b.y, a.z + b.z);
}

Vec3 scale(Vec3 v, double s) {
    return vec3(v.x * s, v.y * s, v.z * s);
}

double dot(Vec3 a, Vec3 b) {
    return a.x * b.x + a.y * b.y + a.z * b.z;
}

Vec3 normalize(Vec3 v) {
    double len = sqrt(dot(v, v));
    return scale(v, 1.0 / len);
}

Vec3 ray_at(Vec3 origin, Vec3 dir, double t) {
    return add(origin, scale(dir, t));
}

Vec3 sky_color(Vec3 dir) {
    double t = 0.5 * (dir.y + 1.0);
    double r = 158 + t * 33;
    double g = 197 + t * 20;
    double b = 255;
    return vec3(r, g, b);
}

int is_in_shadow(Vec3 point) {
    // Simple sphere at origin with radius 2
    return dot(point, point) < 4.0;
}

Vec3 ground_color(Vec3 point) {
    if (is_in_shadow(point)) {
        return vec3(51, 10, 10);
    }

    int x = (int)floor(point.x);
    int z = (int)floor(point.z);
    if ((x + z) % 2 == 0) {
        return vec3(152, 152, 152);
    } else {
        return vec3(67, 67, 67);
    }
}

Vec3 ray_create(int x, int y) {
    double u = (x - WIDTH/2.0) / WIDTH;
    double v = (HEIGHT/2.0 - y) / HEIGHT;
    return normalize(vec3(u, v, -1.0));
}

Vec3 trace_ray(Vec3 origin, Vec3 dir) {
    // Check ground plane intersection (y = 0)
    if (dir.y < 0) {
        double t = -origin.y / dir.y;
        if (t > 0) {
            Vec3 hit_point = ray_at(origin, dir, t);
            return ground_color(hit_point);
        }
    }

    return sky_color(dir);
}

int main() {
    printf("Creating high-resolution image: %dx%d\n", WIDTH, HEIGHT);
    printf("This will be downsampled with ffmpeg after rendering\n");
    printf("Rendering high-resolution image...\n");

    FILE *f = fopen("image.ppm", "w");
    fprintf(f, "P3\n%d %d\n255\n", WIDTH, HEIGHT);

    Vec3 camera = vec3(0, 1, 0);

    for (int y = 0; y < HEIGHT; y++) {
        if (y % (HEIGHT/10) == 0) {
            printf("Progress: %.1f%%\n", y * 100.0 / HEIGHT);
        }

        for (int x = 0; x < WIDTH; x++) {
            Vec3 ray_dir = ray_create(x, y);
            Vec3 color = trace_ray(camera, ray_dir);
            fprintf(f, "%.0f %.0f %.0f\n", color.x, color.y, color.z);
        }
    }

    printf("Progress: 99.8%%\n");
    printf("Rendering complete\n");
    printf("Wrote image to image.ppm\n");
    printf("Done.\n");

    fclose(f);
    return 0;
}
EOF
